    <div class="flex items-center my-4">
      <h3 v-if="viewMode === 'CREATE'" class="text-3xl whitespace-nowrap mr-3">
        Foydalanuvchilarni qʻoshish
      </h3>
      <h3 v-else class="text-3xl whitespace-nowrap mr-3">
        Фойдаланувчиларни таҳрирлаш
      </h3>
      <div class="h-[1px] w-full bg-[#D9DCDD] rounded-md"></div>
    </div>
    <form @submit="onSubmit">
      <section class="grid grid-cols-2 md:grid-cols-3 gap-4 2xl:w-[90%]">
        <div class="form_wrapper my-3">
          <label class="input_label" for="username">
