          </label>
          <input id="username" v-model="username" class="base_input" placeholder="Логин киритинг" name="username" type="text">
          <span class="error_message">{{ usernameError }}</span>
        </div>
        <div class="form_wrapper my-3">
          <label class="input_label" for="password">
