          </label>
          <input id="password" v-model="password" class="base_input" placeholder="Паролни киритинг" name="password" type="text">
          <span class="error_message">{{ passwordError }}</span>
        </div>
        <div class="form_wrapper my-3">
          <label class="input_label" for="rePassword">
            Паролни қайта киритинг
          </label>
          <input id="rePassword" v-model="rePassword" class="base_input" placeholder="Паролни қайта киритинг" name="rePassword" type="text">
          <span class="error_message">{{ rePasswordError }}</span>
        </div>
        <div class="form_wrapper my-3">
          <label class="input_label" for="firstName">
            Ismi
          </label>
          <input id="firstName" v-model="firstName" class="base_input" placeholder="Ismi" name="firstName" type="text">
          <span class="error_message">{{ firstNameError }}</span>
        </div>
        <div class="form_wrapper my-3">
          <label class="input_label" for="lastName">
            Familiyasi
          </label>
          <input id="lastName" v-model="lastName" class="base_input" placeholder="Familiyasi" name="lastName" type="text">
          <span class="error_message">{{ lastNameError }}</span>
        </div>
        <div class="form_wrapper my-3">
          <label class="input_label" for="fatherName">
            Sharifi
          </label>
          <input id="fatherName" v-model="fatherName" class="base_input" placeholder="Sharifi" name="fatherName" type="text">
          <span class="error_message">{{ fatherNameError }}</span>
        </div>
        <div class="form_wrapper my-3">
          <label class="input_label" for="phoneNumber">
            Телефон рақами
          </label>
          <input
            id="phoneNumber" v-model="phoneNumber" v-maska="'+998 ## ### ## ##'" class="base_input" placeholder="Телефон рақами" name="phoneNumber"
            type="text"
          >
          <span class="error_message">{{ phoneNumberError }}</span>
        </div>
        <div class="form_wrapper my-3">
          <label class="input_label" for="email">
            Email
          </label>
          <input id="email" v-model="email" class="base_input" placeholder="Email" name="email" type="email">
          <span class="error_message">{{ emailError }}</span>
        </div>
        <div class="form_wrapper my-3">
          <label class="input_label" for="organId">
            Ташкилоти
          </label>
          <select
            id="organId" v-model="organId" name="organId"
            class="base_input"
          >
            <option value="" disabled selected>
              Ташкилоти
            </option>
            <option v-for="org in organizationList" :key="org.id" :value="org.id">
              {{ org.name }}
            </option>
          </select>
          <span class="error_message">{{ organIdError }}</span>
        </div>
        <div class="form_wrapper my-3">
          <label class="input_label" for="directionId">
            Йўналиш
          </label>
          <select id="directionId" v-model="directionId" name="directionId" class="base_input">
            <option value="" disabled selected>
              Йўналишни танланг
            </option>
            <option v-for="dir in jobDirectionList" :key="dir.id" :value="dir.id">
              {{ dir.name }}
            </option>
          </select>
          <span class="error_message">{{ directionIdError }}</span>
        </div>
        <div class="form_wrapper my-3">
          <label class="input_label" for="position">
            Лавозими
          </label>
          <input id="position" v-model="position" class="base_input" placeholder="Лавозими" name="position" type="text">
          <span class="error_message">{{ positionError }}</span>
        </div>
        <div class="form_wrapper my-3">
          <label class="input_label" for="chiefId">
            Бошлиғини танлаш
          </label>
          <select id="chiefId" v-model="chiefId" name="chiefId" class="base_input">
            <option value="" selected>
              Бошлиғини танланг
            </option>
            <option v-for="chief in chiefList" :key="chief.id" :value="chief.id">
              {{ chief.lastName }} {{ chief.firstName }} {{ chief.fatherName }}
            </option>
          </select>
          <span class="error_message">{{ chiefIdError }}</span>
        </div>
        <div class="form_wrapper my-3">
          <label class="input_label" for="role">
            Rol
          </label>
          <select id="role" v-model="role" name="role" class="base_input">
            <option value="" disabled selected>
              Rol tanlang
            </option>
            <option v-for="r in rolesList" :key="r" :value="r">
              {{ r }}
            </option>
          </select>
          <span class="error_message">{{ roleError }}</span>
        </div>
        <div class="form_wrapper my-3">
          <label class="input_label" for="officeNumber">
            Ишхона телефони
          </label>
          <input
            id="officeNumber" v-model="officeNumber" v-maska="'+998 ## ### ## ##'" class="base_input" placeholder="+998"
            name="officeNumber" type="text"
          >
          <span class="error_message">{{ officeNumberError }}</span>
        </div>
      </section>
      <section>
        <div class="flex items-center my-4">
          <h3 class="text-xl whitespace-nowrap mr-3">
            Foydalanuvchiga biriktirilgan mashina
          </h3>
          <div class="h-[1px] w-full bg-[#D9DCDD] rounded-md"></div>
          <button class="ml-2 focus:outline-none" @click.prevent="toggleCarDriverMode">
            <Icon v-if="!carDriverMode" class="" icon="mdi:plus-circle" width="40" />
            <Icon v-else class="" icon="mdi:minus-circle" width="40" />
          </button>
        </div>
        <div v-if="carDriverMode" class="grid grid-cols-2 md:grid-cols-3 gap-4 2xl:w-[90%]">
          <div class="form_wrapper my-3">
            <label class="input_label" for="carDriver">
              carDriver
            </label>
            <input id="carDriver" v-model="carDriver" class="base_input" placeholder="carDriver" name="carDriver" type="text">
            <span class="error_message">{{ carDriverError }}</span>
          </div>
          <div class="form_wrapper my-3">
            <label class="input_label" for="carDriverPhoneNumber">
              carDriverPhoneNumber
            </label>
            <input
              id="carDriverPhoneNumber" v-model="carDriverPhoneNumber" v-maska="'+998 ## ### ## ##'" class="base_input" placeholder="+998" name="carDriverPhoneNumber"
              type="text"
            >
            <span class="error_message">{{ carDriverPhoneNumberError }}</span>
          </div>
          <div class="form_wrapper my-3">
            <label class="input_label" for="carNumber">
              carNumber
            </label>
            <input id="carNumber" v-model="carNumber" class="base_input" placeholder="carNumber" name="carNumber" type="text">
            <span class="error_message">{{ carNumberError }}</span>
          </div>
          <div class="form_wrapper my-3">
            <label class="input_label" for="carModel">
              carModel
            </label>
            <input id="carModel" v-model="carModel" class="base_input" placeholder="carModel" name="carModel" type="text">
            <span class="error_message">{{ carModelError }}</span>
          </div>
        </div>
      </section>
      <button class="px-3 my-2 py-2 border bg-primary text-white rounded-md" type="submit">
        <span v-if="viewMode === 'CREATE'">
          Foydalanuvchini qoʻshish
        </span>
        <span v-else>
          Tahrirlashni tugatish
        </span>
      </button>
    </form>
  </div>
</template>

<script setup>
import GoBackBtn from  '../components/GoBackBtn'
import {computed, defineComponent, onMounted, ref, watch} from "vue";
import useJobDirectionsList from "../hooks/useJobDirectionsList";
import { Icon } from '@iconify/vue';
import useOrganizationList from "../hooks/useOrganizationList";
import {useField, useForm} from "vee-validate";
const {handleSubmit, isSubmitting, resetForm} = useForm();
import * as yup from "yup";
import axios from "../plugins/axios";
import useScrollToError from "../hooks/useScrollToError";
import {useStore} from "vuex";
import {useRoute, useRouter} from "vue-router";

defineComponent({GoBackBtn,Icon})

const viewMode  = ref('CREATE')

const {jobDirectionList,fetchJobDirectionListByOrganizationId} = useJobDirectionsList()
const {organizationList} = useOrganizationList()
const {scrollToError} = useScrollToError()
const store = useStore()
const route = useRoute()
const router = useRouter()


onMounted(async()=>{
  if( route.name === 'edit-user-admin' ){
    viewMode.value = 'EDIT'
    const resp = (await axios.get('/api/user/for-admin/'+route.params.id)).data.data
    rewriteFields(resp)
  }
  await fetchUserRoles()
})

const rewriteFields = (resp)=>{
  email.value = resp?.email
  username.value = resp?.username
  phoneNumber.value = resp?.phoneNumber
  officeNumber.value = resp?.officeNumber
  lastName.value = resp?.lastName
  firstName.value = resp?.firstName
  fatherName.value = resp?.fatherName
  position.value = resp?.position
  chiefId.value = resp?.chiefId
  organId.value = resp?.organisationId
  directionId.value = resp?.directionId
  role.value = resp?.roleLabel
  if(resp.companyCar){
    carDriverMode.value = true
    carDriver.value = resp.companyCar.driver
    carNumber.value = resp.companyCar.number
    carModel.value = resp.companyCar.model
    carDriverPhoneNumber.value = resp.companyCar.driverPhoneNumber
  }
}

const chiefList = ref([])

const fetchUsersChief = async () =>{
  chiefList.value = (await axios.get('/api/user/chief',{
    params:{
      directionId:directionId.value
    }
  })).data
  console.log(chiefList.value)
}
const fetchUserRoles = async () =>{
  rolesList.value = (await axios.get('/api/info/role',{
    params:{
      directionId:directionId.value
    }
  })).data
}

const rolesList = ref([])




const carDriverMode = ref(false)
function toggleCarDriverMode(){
  carDriverMode.value = !carDriverMode.value
}
function cardDriverBlockIsNotEmpty(){
  return  carModel.value && carNumber.value && carDriverPhoneNumber.value && carDriver.value
}

function onInvalidSubmit({values, errors, results}) {
  console.log(errors)
  scrollToError(Object.keys(errors)[0])
}

const onSubmit  = handleSubmit(async({carDriver,carModel,carNumber,carDriverPhoneNumber,officeNumber,phoneNumber,...values})=>{
  try {
    let payloadObject = {
      ...values,
      officeNumber: officeNumber.split(' ').join(''),
      phoneNumber: phoneNumber.split(' ').join(''),
    }

    if(carDriverMode.value && cardDriverBlockIsNotEmpty()){
      payloadObject = {
        ...payloadObject,
        companyCar: {
          driver:carDriver,
          model	:carModel,
          number	:carNumber,
          driverPhoneNumber:carDriverPhoneNumber.split(' ').join('')
        }
      }
    }

    let resp;
    if(viewMode.value === 'CREATE'){
       resp = (await axios.post('/api/user', payloadObject)).data
        await store.dispatch('toast',{
          type:'success',
          message:resp?.message
        })
    }
    if(viewMode.value === 'EDIT'){
      resp = (await axios.put(`/api/user/from-admin/${route.params.id}`, payloadObject)).data
      await store.dispatch('toast',{
        type:'success',
        message:resp?.message
      })
      await router.back()
    }
    resetForm()
  } catch (e) {
  await store.dispatch('errorHandler', e)
  }
},onInvalidSubmit)

const validatorMessageGenerator = ({path}) => {
  return `Ушбу майдон тўлдирилиши шарт`;
};
const minValidatorMessageGenerator = (args) => {
  return `Eng kami ${args.min}ta belgi bo\'lishi kerak`
}

const {
  value: username,
  errorMessage:usernameError
} = useField('username', yup.string().required(validatorMessageGenerator).min(5,minValidatorMessageGenerator), {initialValue: ''});
const {
  value: password,
  errorMessage: passwordError
} = useField('password', yup.string().required(validatorMessageGenerator).min(8,minValidatorMessageGenerator), {initialValue: ''});
const {
  value: rePassword,
  errorMessage: rePasswordError
} = useField('rePassword', yup.string().required(validatorMessageGenerator).min(8,minValidatorMessageGenerator), {initialValue: ''});
const {
  value: firstName,
  errorMessage: firstNameError
} = useField('firstName', yup.string().required(validatorMessageGenerator), {initialValue: ''});
const {
  value: lastName,
  errorMessage: lastNameError
} = useField('lastName', yup.string().required(validatorMessageGenerator), {initialValue: ''})
const {
  value: fatherName,
  errorMessage: fatherNameError
} = useField('fatherName', yup.string().required(validatorMessageGenerator), {initialValue: ''});
const {
  value: phoneNumber,
  errorMessage: phoneNumberError
} = useField('phoneNumber', yup.string().required(validatorMessageGenerator), {initialValue: '  '})
const {
  value: email,
  errorMessage: emailError
} = useField('email', yup.string(), {initialValue: ''});

const {
  value: position,
  errorMessage: positionError
} = useField('position', yup.string(), {initialValue: ''});
const {
  value: officeNumber,
  errorMessage: officeNumberError
} = useField('officeNumber', yup.string().required(validatorMessageGenerator), {initialValue: ''});

const {
  value: organId,
  errorMessage:organIdError
} = useField('organId', yup.string(), {initialValue: ''});

const {
  value: directionId,
  errorMessage:directionIdError
} = useField('directionId', yup.string().required(validatorMessageGenerator), {initialValue: ''});

const {
  value: chiefId,
  errorMessage:chiefIdError
} = useField('chiefId', yup.mixed(), {initialValue: ''});

const {
  value: role,
  errorMessage:roleError
} = useField('role', yup.string().required(validatorMessageGenerator), {initialValue: ''});


watch(()=>directionId.value,async(val)=>{
  if(val){
    await fetchUsersChief()
  }
})
watch(()=>organId.value,async(val)=>{
  if(val){
    await fetchJobDirectionListByOrganizationId({
      target:{
        value : val
      }
    })
  }
})

const ruleForCardDriverBlock = computed(()=>{
  return carDriverMode.value ? yup.string().required(validatorMessageGenerator) : yup.string()
})

const {
  value: carModel,
  errorMessage:carModelError
} = useField('carModel',ruleForCardDriverBlock , {initialValue: ''});

const {
  value: carNumber,
  errorMessage:carNumberError
} = useField('carNumber', ruleForCardDriverBlock, {initialValue: ''});

const {
  value: carDriverPhoneNumber,
  errorMessage:carDriverPhoneNumberError
} = useField('carDriverPhoneNumber', ruleForCardDriverBlock, {initialValue: ''});

const {
  value: carDriver,
  errorMessage:carDriverError
} = useField('carDriver', ruleForCardDriverBlock, {initialValue: ''});


</script>

