import {onMounted, ref} from 'vue'
import axios from "../plugins/axios";


export default function useJobDirectionsList() {
    const jobDirectionList = ref([])
    const fetchJobDirectionListByOrganizationId = async ({target}) => {
        jobDirectionList.value = ((await axios.get('/api/direction/all',{
            params:{
                organId:target.value
            }
        })).data).data
    }
    // onMounted(async () => {
    //     await fetchJobDirectionList()
    // })

    return {
        jobDirectionList,
        fetchJobDirectionListByOrganizationId
    }
}